#!/bin/bash\n\"\"\"\nfdi_office_automation setup script\nInitialize environment, dependencies, and configuration for office automation.\n\nUsage:\n    bash setup.sh\n    bash setup.sh --with-systemd\n\"\"\"\n\nset -e\n\necho \"========================================\"\necho \"fdi_office_automation SETUP\"\necho \"========================================\"\n\n# Colors for output\nGREEN='\\033[0;32m'\nYELLOW='\\033[1;33m'\nRED='\\033[0;31m'\nNC='\\033[0m' # No Color\n\n# Get script directory\nSCRIPT_DIR=\"$( cd \"$( dirname \"${BASH_SOURCE[0]}\" )\" && pwd )\"\n\necho -e \"${GREEN}Step 1: Create .env from template${NC}\"\nif [ ! -f \"$SCRIPT_DIR/.env\" ]; then\n    echo \"Creating .env file...\"\n    cp \"$SCRIPT_DIR/.env.template\" \"$SCRIPT_DIR/.env\"\n    echo -e \"${YELLOW}⚠️  Please edit .env with your paths and Docker container names${NC}\"\n    echo \"   nano $SCRIPT_DIR/.env\"\nelse\n    echo \".env already exists\"\nfi\n\necho -e \"${GREEN}Step 2: Create Python virtual environment${NC}\"\nif [ ! -d \"$SCRIPT_DIR/venv\" ]; then\n    echo \"Creating venv...\"\n    python3 -m venv \"$SCRIPT_DIR/venv\"\n    source \"$SCRIPT_DIR/venv/bin/activate\"\n    pip install --upgrade pip\n    pip install watchdog pyyaml requests\n    echo -e \"${GREEN}✓ Virtual environment created${NC}\"\nelse\n    echo \"venv already exists\"\n    source \"$SCRIPT_DIR/venv/bin/activate\"\nfi\n\necho -e \"${GREEN}Step 3: Create output directories${NC}\"\nmkdir -p \"$SCRIPT_DIR/logs\"\nmkdir -p \"$SCRIPT_DIR/outputs_admin\"\necho -e \"${GREEN}✓ Directories created${NC}\"\n\necho -e \"${GREEN}Step 4: Verify configuration${NC}\"\necho \"Configuration paths:\"\necho \"  SIG_BASE: $(grep SIG_BASE $SCRIPT_DIR/.env | cut -d= -f2)\"\necho \"  PREDIOS_FOLDER: $(grep PREDIOS_FOLDER $SCRIPT_DIR/.env | cut -d= -f2)\"\necho \"  LOG_DIR: $(grep LOG_DIR $SCRIPT_DIR/.env | cut -d= -f2)\"\n\necho -e \"${GREEN}Step 5: Test imports${NC}\"\npython3 -c \"\nimport sys\nsys.path.insert(0, '$SCRIPT_DIR')\nfrom modelos.config import QFIELD_DISCOVERY\nfrom modelos.helpers import logger\nprint('✓ Core modules importable')\n\nprint('✓ QField layer discovery loaded')\nprint(f'  - Layer patterns: {len(QFIELD_DISCOVERY[\\\"discovery_patterns\\\"])} types')\nfor layer_type in QFIELD_DISCOVERY['discovery_patterns']:\n    print(f'    - {layer_type}')\n\"\n\necho \"\"\necho -e \"${GREEN}========================================${NC}\"\necho -e \"${GREEN}Setup Complete!${NC}\"\necho -e \"${GREEN}========================================${NC}\"\necho \"\"\necho \"Next steps:\"\necho \"1. Edit configuration: nano $SCRIPT_DIR/.env\"\necho \"2. Test overnight predios processor:\"\necho \"   $SCRIPT_DIR/venv/bin/python3 $SCRIPT_DIR/scripts/overnight_predios_processor.py --dry-run\"\necho \"3. Test project orchestrator:\"\necho \"   $SCRIPT_DIR/venv/bin/python3 $SCRIPT_DIR/scripts/project_orchestrator.py --list-projects\"\necho \"4. Start QField watcher:\"\necho \"   $SCRIPT_DIR/venv/bin/python3 $SCRIPT_DIR/scripts/qfield_watcher.py --scan-once\"\necho \"\"\necho \"For scheduling with cron:\"\necho \"  0 22 * * * cd $SCRIPT_DIR && venv/bin/python3 scripts/overnight_predios_processor.py --execute\"\necho \"  0 6 * * *  cd $SCRIPT_DIR && venv/bin/python3 scripts/overnight_rebuild_trigger.py --execute\"\necho \"\"\n\nif [ \"$1\" == \"--with-systemd\" ]; then\n    echo -e \"${YELLOW}Systemd service setup${NC}\"\n    echo \"Note: Systemd service setup requires manual steps. See README.md for details.\"\nfi\n"